// 您需要定义 `async` 事件处理程序
export default defineEventHandler(async event => {
  // 调用 `useTranslation`，以便返回翻译函数
  const t = await useTranslation(event)
  return {
    // 使用 locale 消息的键调用翻译函数，
    // 翻译函数有一些重载
    hello: t('hello')
  }
})

